'use strict';

// MODULES //

import rotr90 from '@stdlib/ndarray-base-rotr90';


// MAIN //

/**
* Rotates a matrix (or a stack of matrices) 90 degrees counterclockwise.
*
* @param {ndarray} x - input array
* @param {integer} k - number of times to rotate by 90 degrees
* @param {boolean} writable - boolean indicating whether the returned ndarray should be writable
* @returns {ndarray} ndarray view
*
* @example
* import array from '@stdlib/ndarray-array';
*
* var x = array( [ [ 1, 2 ], [ 3, 4 ] ] );
* // returns <ndarray>[ [ 1, 2 ], [ 3, 4 ] ]
*
* var y = rotl90( x, 1, false );
* // returns <ndarray>[ [ 2, 4 ], [ 1, 3 ] ]
*/
function rotl90( x, k, writable ) {
	return rotr90( x, -k, writable );
}


// EXPORTS //

export default rotl90;
